package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.FiscaleConstant;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.jpa.gl.FiscaleConstantPK;
import be.schaubroeck.lpb.tools.service.FiscaleConstantService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.List;

public class CachedFiscaleConstantService implements CachedService, FiscaleConstantService {

    @Autowired
    private FiscaleConstantService fiscaleConstantService;

    private static final ThreadLocal<CachedFiscaleConstantBuffer> BUFFER = new ThreadLocal<>();

    public CachedFiscaleConstantService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public void clearCache() {
        CachedFiscaleConstantService.getBuffer().clear();
    }

    @Override
    public FiscaleConstant getByDate(LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedFiscaleConstantService.getByDate");
        CachedFiscaleConstantBuffer buffer = CachedFiscaleConstantService.getBuffer();
        if (buffer.get() == null) {
            buffer.set(fiscaleConstantService.findAll());
        }

        FiscaleConstant result = zoekLijst(buffer.get(), datum);

        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    private FiscaleConstant zoekLijst(List<FiscaleConstant> lijst, LocalDate datum) {
        FiscaleConstant result = null;
        for (FiscaleConstant fiscaleConstant : lijst) {
            LocalDateInterval periode = new LocalDateInterval(fiscaleConstant.getBeginDatum(), fiscaleConstant.getEindDatum());
            if (periode.contains(datum) && fiscaleConstant.getRegultijdstip() == null) {
                result = fiscaleConstant;
                break;
            }
        }
        return result;
    }

    private static class CachedFiscaleConstantBuffer {

        private List<FiscaleConstant> fiscaleConstantBuffer = null;

        public List<FiscaleConstant> get() {
            return fiscaleConstantBuffer;
        }

        public void set(List<FiscaleConstant> lijst) {
            fiscaleConstantBuffer = lijst;
        }

        public void clear() {
            fiscaleConstantBuffer = null;
        }
    }

    private static CachedFiscaleConstantBuffer getBuffer() {
        CachedFiscaleConstantBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedFiscaleConstantBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<FiscaleConstant> findAll() {
        return fiscaleConstantService.findAll();
    }

    @Override
    public FiscaleConstant create(FiscaleConstant constant) {
        return fiscaleConstantService.create(constant);
    }

    @Override
    public FiscaleConstant update(FiscaleConstant constant) {
        return fiscaleConstantService.update(constant);
    }

    @Override
    public void delete(FiscaleConstant constant) {
        fiscaleConstantService.delete(constant);
    }

    @Override
    public FiscaleConstant getById(FiscaleConstantPK id) {
        return fiscaleConstantService.getById(id);
    }

    @Override
    public FiscaleConstant getById(FiscaleConstantPK id, String fetchFields) {
        return fiscaleConstantService.getById(id, fetchFields);
    }


    @Override
    public FiscaleConstant getByCriteria(CriteriaBuilder cb) {
        return fiscaleConstantService.getByCriteria(cb);
    }


    @Override
    public List<FiscaleConstant> findAll(String fetchFields) {
        return fiscaleConstantService.findAll(fetchFields);
    }

    @Override
    public List<FiscaleConstant> findByCriteria(CriteriaBuilder cb) {
        return fiscaleConstantService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return fiscaleConstantService.countByCriteria(cb);
    }


}
